22	function prepareJsonFixtureResponse(
23	  filename: string,
24	  headers?: Record<string, string>,
25	) {
26	  server.urls['https://api.openai.com/v1/images/generations'].response = {
27	    type: 'json-value',
28	    headers,
29	    body: JSON.parse(
30	      fs.readFileSync(`src/image/__fixtures__/${filename}.json`, 'utf8'),
31	    ),
32	  };
33	}
