103	export function createFireworks(
104	  options: FireworksProviderSettings = {},
105	): FireworksProvider {
106	  const baseURL = withoutTrailingSlash(options.baseURL ?? defaultBaseURL);
107	  const getHeaders = () =>
108	    withUserAgentSuffix(
109	      {
110	        Authorization: `Bearer ${loadApiKey({
111	          apiKey: options.apiKey,
112	          environmentVariableName: 'FIREWORKS_API_KEY',
113	          description: 'Fireworks API key',
114	        })}`,
115	        ...options.headers,
116	      },
117	      `ai-sdk/fireworks/${VERSION}`,
118	    );
119	
120	  interface CommonModelConfig {
121	    provider: string;
122	    url: ({ path }: { path: string }) => string;
123	    headers: () => Record<string, string>;
124	    fetch?: FetchFunction;
125	  }
126	
127	  const getCommonModelConfig = (modelType: string): CommonModelConfig => ({
128	    provider: `fireworks.${modelType}`,
129	    url: ({ path }) => `${baseURL}${path}`,
130	    headers: getHeaders,
131	    fetch: options.fetch,
132	  });
133	
134	  const createChatModel = (modelId: FireworksChatModelId) => {
135	    return new OpenAICompatibleChatLanguageModel(modelId, {
136	      ...getCommonModelConfig('chat'),
137	      errorStructure: fireworksErrorStructure,
138	      transformRequestBody: args => {
139	        const thinking = args.thinking as
140	          | { type?: string; budgetTokens?: number }
141	          | undefined;
142	        const reasoningHistory = args.reasoningHistory as string | undefined;
143	
144	        const { thinking: _, reasoningHistory: __, ...rest } = args;
145	
146	        return {
147	          ...rest,
148	          ...(thinking && {
149	            thinking: {
150	              type: thinking.type,
151	              ...(thinking.budgetTokens !== undefined && {
152	                budget_tokens: thinking.budgetTokens,
153	              }),
154	            },
155	          }),
156	          ...(reasoningHistory && {
157	            reasoning_history: reasoningHistory,
158	          }),
159	        };
160	      },
161	    });
162	  };
163	
164	  const createCompletionModel = (modelId: FireworksCompletionModelId) =>
165	    new OpenAICompatibleCompletionLanguageModel(modelId, {
166	      ...getCommonModelConfig('completion'),
167	      errorStructure: fireworksErrorStructure,
168	    });
169	
170	  const createEmbeddingModel = (modelId: FireworksEmbeddingModelId) =>
171	    new OpenAICompatibleEmbeddingModel(modelId, {
172	      ...getCommonModelConfig('embedding'),
173	      errorStructure: fireworksErrorStructure,
174	    });
175	
176	  const createImageModel = (modelId: FireworksImageModelId) =>
177	    new FireworksImageModel(modelId, {
178	      ...getCommonModelConfig('image'),
179	      baseURL: baseURL ?? defaultBaseURL,
180	    });
181	
182	  const provider = (modelId: FireworksChatModelId) => createChatModel(modelId);
183	
184	  provider.specificationVersion = 'v3' as const;
185	  provider.completionModel = createCompletionModel;
186	  provider.chatModel = createChatModel;
187	  provider.languageModel = createChatModel;
188	  provider.embeddingModel = createEmbeddingModel;
189	  provider.textEmbeddingModel = createEmbeddingModel;
190	  provider.image = createImageModel;
191	  provider.imageModel = createImageModel;
192	  return provider;
193	}
