126	export function createGoogleGenerativeAI(
127	  options: GoogleGenerativeAIProviderSettings = {},
128	): GoogleGenerativeAIProvider {
129	  const baseURL =
130	    withoutTrailingSlash(options.baseURL) ??
131	    'https://generativelanguage.googleapis.com/v1beta';
132	
133	  const providerName = options.name ?? 'google.generative-ai';
134	
135	  const getHeaders = () =>
136	    withUserAgentSuffix(
137	      {
138	        'x-goog-api-key': loadApiKey({
139	          apiKey: options.apiKey,
140	          environmentVariableName: 'GOOGLE_GENERATIVE_AI_API_KEY',
141	          description: 'Google Generative AI',
142	        }),
143	        ...options.headers,
144	      },
145	      `ai-sdk/google/${VERSION}`,
146	    );
147	
148	  const createChatModel = (modelId: GoogleGenerativeAIModelId) =>
149	    new GoogleGenerativeAILanguageModel(modelId, {
150	      provider: providerName,
151	      baseURL,
152	      headers: getHeaders,
153	      generateId: options.generateId ?? generateId,
154	      supportedUrls: () => ({
155	        '*': [
156	          // Google Generative Language "files" endpoint
157	          // e.g. https://generativelanguage.googleapis.com/v1beta/files/...
158	          new RegExp(`^${baseURL}/files/.*$`),
159	          // YouTube URLs (public or unlisted videos)
160	          new RegExp(
161	            `^https://(?:www\\.)?youtube\\.com/watch\\?v=[\\w-]+(?:&[\\w=&.-]*)?$`,
162	          ),
163	          new RegExp(`^https://youtu\\.be/[\\w-]+(?:\\?[\\w=&.-]*)?$`),
164	        ],
165	      }),
166	      fetch: options.fetch,
167	    });
168	
169	  const createEmbeddingModel = (modelId: GoogleGenerativeAIEmbeddingModelId) =>
170	    new GoogleGenerativeAIEmbeddingModel(modelId, {
171	      provider: providerName,
172	      baseURL,
173	      headers: getHeaders,
174	      fetch: options.fetch,
175	    });
176	
177	  const createImageModel = (
178	    modelId: GoogleGenerativeAIImageModelId,
179	    settings: GoogleGenerativeAIImageSettings = {},
180	  ) =>
181	    new GoogleGenerativeAIImageModel(modelId, settings, {
182	      provider: providerName,
183	      baseURL,
184	      headers: getHeaders,
185	      fetch: options.fetch,
186	    });
187	
188	  const createVideoModel = (modelId: GoogleGenerativeAIVideoModelId) =>
189	    new GoogleGenerativeAIVideoModel(modelId, {
190	      provider: providerName,
191	      baseURL,
192	      headers: getHeaders,
193	      fetch: options.fetch,
194	      generateId: options.generateId ?? generateId,
195	    });
196	
197	  const provider = function (modelId: GoogleGenerativeAIModelId) {
198	    if (new.target) {
