### 7. PROVIDER INTERFACE & FACTORY FUNCTION

**Pattern 1: Full-Featured Provider (Fireworks)**

```typescript
export interface FireworksProviderSettings {
  apiKey?: string;
  baseURL?: string;
  headers?: Record<string, string>;
  fetch?: FetchFunction;
}

export interface FireworksProvider extends ProviderV3 {
  (modelId: FireworksChatModelId): LanguageModelV3;
  chatModel(modelId: FireworksChatModelId): LanguageModelV3;
  completionModel(modelId: FireworksCompletionModelId): LanguageModelV3;
  languageModel(modelId: FireworksChatModelId): LanguageModelV3;
  embeddingModel(modelId: FireworksEmbeddingModelId): EmbeddingModelV3;
  textEmbeddingModel(modelId: FireworksEmbeddingModelId): EmbeddingModelV3;
  image(modelId: FireworksImageModelId): ImageModelV3;
  imageModel(modelId: FireworksImageModelId): ImageModelV3;
}

export function createFireworks(options: FireworksProviderSettings = {}): FireworksProvider {
  const baseURL = withoutTrailingSlash(options.baseURL ?? defaultBaseURL);
  const getHeaders = () =>
    withUserAgentSuffix(
      {
        Authorization: `Bearer ${loadApiKey({
          apiKey: options.apiKey,
          environmentVariableName: 'FIREWORKS_API_KEY',
          description: 'Fireworks',
        })}`,
        ...options.headers,
      },
      `ai-sdk/fireworks/${VERSION}`,
    );

  const provider = (modelId: FireworksChatModelId) => createChatModel(modelId);
  provider.specificationVersion = 'v3' as const;
  provider.chatModel = createChatModel;
  provider.completionModel = createCompletionModel;
  provider.languageModel = createChatModel;
  provider.embeddingModel = createEmbeddingModel;
  provider.textEmbeddingModel = createEmbeddingModel;
  provider.image = createImageModel;
  provider.imageModel = createImageModel;
  return provider;
}

export const fireworks = createFireworks();
```

**Pattern 2: Image-Only Provider (Replicate/Black Forest Labs)**

```typescript
export interface ReplicateProviderSettings {
  apiToken?: string;
  baseURL?: string;
  headers?: Record<string, string>;
  fetch?: FetchFunction;
}

export interface ReplicateProvider extends ProviderV3 {
  image(modelId: ReplicateImageModelId): ReplicateImageModel;
  imageModel(modelId: ReplicateImageModelId): ReplicateImageModel;
  textEmbeddingModel(modelId: string): never;
  video(modelId: ReplicateVideoModelId): Experimental_VideoModelV3;
  videoModel(modelId: ReplicateVideoModelId): Experimental_VideoModelV3;
}

export function createReplicate(options: ReplicateProviderSettings = {}): ReplicateProvider {
  const getHeaders = () =>
    withUserAgentSuffix(
      {
        Authorization: `Bearer ${loadApiKey({
          apiKey: options.apiToken,
          environmentVariableName: 'REPLICATE_API_TOKEN',
          description: 'Replicate',
        })}`,
        ...options.headers,
      },
      `ai-sdk/replicate/${VERSION}`,
    );

  const createImageModel = (modelId: ReplicateImageModelId) =>
    new ReplicateImageModel(modelId, { /* config */ });

  const embeddingModel = (modelId: string) => {
    throw new NoSuchModelError({ modelId, modelType: 'embeddingModel' });
  };

  return {
    specificationVersion: 'v3',
    image: createImageModel,
    imageModel: createImageModel,
    languageModel: (modelId: string) => {
      throw new NoSuchModelError({ modelId, modelType: 'languageModel' });
    },
    embeddingModel,
    textEmbeddingModel: embeddingModel,
    video: createVideoModel,
    videoModel: createVideoModel,
  };
}

export const replicate = createReplicate();
```

**Key Points:**
- Provider extends `ProviderV3` from `@ai-sdk/provider`
- Implements `specificationVersion = 'v3'`
- Factory function accepts provider settings (API key, base URL, headers, custom fetch)
- Default instance exported for convenience
- Image-only providers throw `NoSuchModelError` for unsupported model types

