import type { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import type { Resolvable } from '@ai-sdk/provider-utils';
import {
  combineHeaders,
  createJsonResponseHandler,
  FetchFunction,
  parseProviderOptions,
  postJsonToApi,
  resolve,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';
import { pixelartImageModelOptionsSchema } from './pixelart-image-options';
import { PixelArtImageModelId } from './pixelart-image-settings';
import { pixelartFailedResponseHandler } from './pixelart-error';

interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers?: Resolvable<Record<string, string | undefined>>;
  fetch?: FetchFunction;
  _internal?: {
    currentDate?: () => Date;
  };
}

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 4;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate(
    options: Parameters<ImageModelV3['doGenerate']>[0],
  ): Promise<Awaited<ReturnType<ImageModelV3['doGenerate']>>> {
    const {
      prompt,
      n,
      size,
      aspectRatio,
      seed,
      providerOptions,
      headers,
      abortSignal,
      files,
      mask,
    } = options;

    const warnings: Array<SharedV3Warning> = [];

    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details:
          'This model does not support aspect ratio. Use the size parameter instead.',
      });
    }

    if (files != null && files.length > 0) {
      warnings.push({
        type: 'unsupported',
        feature: 'files',
        details: 'This model does not support image editing.',
      });
    }

    if (mask != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'mask',
        details: 'This model does not support inpainting with masks.',
      });
    }

    const pixelartOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelartImageModelOptionsSchema,
    });

    const requestBody: Record<string, unknown> = {
      model: this.modelId,
      prompt,
      n,
    };

    if (size != null) {
      requestBody.size = size;
    }

    if (seed != null) {
      requestBody.seed = seed;
    }

    if (pixelartOptions?.style != null) {
      requestBody.style = pixelartOptions.style;
    }

    if (pixelartOptions?.pixelDensity != null) {
      requestBody.pixel_density = pixelartOptions.pixelDensity;
    }

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();

    const { value, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generations`,
      headers: combineHeaders(
        await resolve(this.config.headers),
        headers,
      ),
      body: requestBody,
      failedResponseHandler: pixelartFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(
        pixelartImageResponseSchema,
      ),
      abortSignal,
      fetch: this.config.fetch,
    });

    return {
      images: value.data.map(item => item.b64_json),
      warnings,
      response: {
        modelId: this.modelId,
        timestamp: currentDate,
        headers: responseHeaders,
      },
      providerMetadata: {
        pixelart: {
          created: value.created,
        },
      },
    };
  }
}

const pixelartImageResponseSchema = z.object({
  created: z.number().nullish(),
  data: z.array(
    z.object({
      b64_json: z.string(),
    }),
  ),
});

import { FetchFunction } from '@ai-sdk/provider-utils';
import { createTestServer } from '@ai-sdk/test-server/with-vitest';
import { describe, expect, it } from 'vitest';
import { PixelArtImageModel } from './pixelart-image-model';

const prompt = 'A cute pixel art cat';

function createBasicModel({
  headers,
  fetch,
  currentDate,
}: {
  headers?: Record<string, string | undefined>;
  fetch?: FetchFunction;
  currentDate?: () => Date;
} = {}) {
  return new PixelArtImageModel('pixelart-standard', {
    provider: 'pixelart.image',
    baseURL: 'https://api.example.com/v1',
    headers: headers ?? { 'api-key': 'test-key' },
    fetch,
    _internal: {
      currentDate,
    },
  });
}

const testImageBase64 = btoa('test-image-binary-content');

describe('PixelArtImageModel', () => {
  const server = createTestServer({
    'https://api.example.com/v1/images/generations': {
      response: {
        type: 'json-value',
        body: {
          created: 1700000000,
          data: [
            {
              b64_json: testImageBase64,
            },
          ],
        },
      },
    },
  });

  describe('constructor', () => {
    it('should expose correct provider and model information', () => {
      const model = createBasicModel();

      expect(model.provider).toBe('pixelart.image');
      expect(model.modelId).toBe('pixelart-standard');
      expect(model.specificationVersion).toBe('v3');
      expect(model.maxImagesPerCall).toBe(4);
    });
  });

  describe('doGenerate', () => {
    it('should pass the correct parameters', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: '256x256',
        aspectRatio: undefined,
        seed: 42,
        providerOptions: {},
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: 'pixelart-standard',
        prompt,
        n: 1,
        size: '256x256',
        seed: 42,
      });
    });

    it('should send provider options (style and pixelDensity)', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 2,
        size: '512x512',
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {
          pixelart: {
            style: 'retro',
            pixelDensity: 16,
          },
        },
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: 'pixelart-standard',
        prompt,
        n: 2,
        size: '512x512',
        style: 'retro',
        pixel_density: 16,
      });
    });

    it('should return base64 images as strings', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(result.images).toHaveLength(1);
      expect(result.images[0]).toBe(testImageBase64);
    });

    it('should return multiple images', async () => {
      server.urls[
        'https://api.example.com/v1/images/generations'
      ].response = {
        type: 'json-value',
        body: {
          created: 1700000000,
          data: [
            { b64_json: testImageBase64 },
            { b64_json: testImageBase64 },
          ],
        },
      };

      const model = createBasicModel();
      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 2,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(result.images).toHaveLength(2);
    });

    it('should pass headers', async () => {
      const modelWithHeaders = createBasicModel({
        headers: {
          'Custom-Provider-Header': 'provider-header-value',
        },
      });

      await modelWithHeaders.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        providerOptions: {},
        headers: {
          'Custom-Request-Header': 'request-header-value',
        },
        size: undefined,
        seed: undefined,
        aspectRatio: undefined,
      });

      expect(server.calls[0].requestHeaders).toStrictEqual({
        'content-type': 'application/json',
        'custom-provider-header': 'provider-header-value',
        'custom-request-header': 'request-header-value',
      });
    });

    it('should handle API errors', async () => {
      server.urls[
        'https://api.example.com/v1/images/generations'
      ].response = {
        type: 'error',
        status: 400,
        body: JSON.stringify({
          error: {
            message: 'Invalid prompt for pixel art generation',
            code: 'invalid_prompt',
          },
        }),
      };

      const model = createBasicModel();
      await expect(
        model.doGenerate({
          prompt,
          files: undefined,
          mask: undefined,
          n: 1,
          providerOptions: {},
          size: undefined,
          seed: undefined,
          aspectRatio: undefined,
        }),
      ).rejects.toMatchObject({
        message: 'Invalid prompt for pixel art generation',
        statusCode: 400,
      });
    });

    it('should omit undefined optional fields from the request body', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      const body = await server.calls[0].requestBodyJson;
      expect(body).toStrictEqual({
        model: 'pixelart-standard',
        prompt,
        n: 1,
      });
      expect(body).not.toHaveProperty('size');
      expect(body).not.toHaveProperty('seed');
      expect(body).not.toHaveProperty('style');
      expect(body).not.toHaveProperty('pixel_density');
    });

    describe('unsupported features', () => {
      it('should warn when aspectRatio is provided', async () => {
        const model = createBasicModel();

        const result = await model.doGenerate({
          prompt,
          files: undefined,
          mask: undefined,
          n: 1,
          size: undefined,
          aspectRatio: '16:9',
          seed: undefined,
          providerOptions: {},
        });

        expect(result.warnings).toContainEqual({
          type: 'unsupported',
          feature: 'aspectRatio',
          details:
            'This model does not support aspect ratio. Use the size parameter instead.',
        });
      });

      it('should warn when files are provided', async () => {
        const model = createBasicModel();

        const result = await model.doGenerate({
          prompt,
          files: [
            {
              type: 'url',
              url: 'https://example.com/input.png',
            },
          ],
          mask: undefined,
          n: 1,
          size: undefined,
          aspectRatio: undefined,
          seed: undefined,
          providerOptions: {},
        });

        expect(result.warnings).toContainEqual({
          type: 'unsupported',
          feature: 'files',
          details: 'This model does not support image editing.',
        });
      });

      it('should warn when mask is provided', async () => {
        const model = createBasicModel();

        const result = await model.doGenerate({
          prompt,
          files: undefined,
          mask: {
            type: 'url',
            url: 'https://example.com/mask.png',
          },
          n: 1,
          size: undefined,
          aspectRatio: undefined,
          seed: undefined,
          providerOptions: {},
        });

        expect(result.warnings).toContainEqual({
          type: 'unsupported',
          feature: 'mask',
          details: 'This model does not support inpainting with masks.',
        });
      });
    });

    describe('response metadata', () => {
      it('should include timestamp, headers, and modelId in response', async () => {
        const testDate = new Date('2024-01-01T00:00:00Z');
        const model = createBasicModel({
          currentDate: () => testDate,
        });

        const result = await model.doGenerate({
          prompt,
          files: undefined,
          mask: undefined,
          n: 1,
          providerOptions: {},
          size: undefined,
          seed: undefined,
          aspectRatio: undefined,
        });

        expect(result.response).toStrictEqual({
          timestamp: testDate,
          modelId: 'pixelart-standard',
          headers: expect.any(Object),
        });
      });

      it('should include provider metadata with created timestamp', async () => {
        const model = createBasicModel();

        const result = await model.doGenerate({
          prompt,
          files: undefined,
          mask: undefined,
          n: 1,
          providerOptions: {},
          size: undefined,
          seed: undefined,
          aspectRatio: undefined,
        });

        expect(result.providerMetadata).toStrictEqual({
          pixelart: {
            created: 1700000000,
          },
        });
      });
    });
  });
});
